import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "react-query";
import { recruitmentAPI } from "../utils/api";
import LoadingSpinner from "../components/common/LoadingSpinner";
import { SparklesIcon } from "@heroicons/react/24/solid";
import toast from "react-hot-toast";
import clsx from "clsx";
const STATUS_COLOR = { applied:"badge-neutral", screening:"badge-info", shortlisted:"badge-success", rejected:"badge-danger", hired:"badge-purple" };
export default function Recruitment() {
  const qc = useQueryClient();
  const [tab, setTab] = useState("jobs");
  const [selectedJob, setSelectedJob] = useState(null);
  const { data: jobsData, isLoading } = useQuery("jobs", () => recruitmentAPI.getJobs({status:"open"}).then(r=>r.data));
  const { data: appsData, isLoading: appsLoading } = useQuery(["applications",selectedJob], () => recruitmentAPI.getApplications({jobId:selectedJob,limit:50}).then(r=>r.data), { enabled:!!selectedJob });
  const { data: stats } = useQuery("recStats2", () => recruitmentAPI.getStats().then(r=>r.data.data));
  const screenMut = useMutation(id=>recruitmentAPI.screenApplication(id), { onSuccess:()=>{toast.success("Screening complete");qc.invalidateQueries(["applications",selectedJob])} });
  const bulkMut = useMutation(()=>recruitmentAPI.bulkScreen(selectedJob), { onSuccess:({data})=>toast.success(`Screened ${data.data.processed} applications`) });
  if (isLoading) return <LoadingSpinner text="Loading recruitment…"/>;
  const jobs = jobsData?.data || [];
  const applications = appsData?.data || [];
  return (
    <div className="space-y-5 animate-in">
      <div><h1 className="page-title">Recruitment</h1><p className="text-slate-500 text-sm mt-0.5">{stats?.openJobs||0} open positions · {stats?.totalApps||0} total applications</p></div>
      <div className="flex gap-2 border-b border-slate-200">{["jobs","applications"].map(t=>(<button key={t} onClick={()=>setTab(t)} className={clsx("px-4 py-2 text-sm font-medium capitalize border-b-2 -mb-px transition-colors",tab===t?"border-primary-500 text-primary-600":"border-transparent text-slate-500 hover:text-slate-700")}>{t}</button>))}</div>
      {tab==="jobs"&&<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">{jobs.map(job=>(<div key={job.id} className="card hover:shadow-card-hover cursor-pointer" onClick={()=>{setSelectedJob(job.id);setTab("applications")}}><div className="flex items-start justify-between mb-2"><div><p className="font-semibold text-slate-900">{job.title}</p><p className="text-sm text-slate-500">{job.department?.name}</p></div><span className="badge badge-success">{job.status}</span></div><div className="flex gap-4 text-xs text-slate-400 mt-3"><span>📍 {job.location||"Remote"}</span><span>⏱ {job.experienceMin}–{job.experienceMax||"+"}y</span><span>🪑 {job.openings}</span></div>{job.requiredSkills?.length>0&&<div className="flex flex-wrap gap-1 mt-3">{job.requiredSkills.slice(0,4).map(s=>(<span key={s} className="px-2 py-0.5 bg-slate-100 text-slate-600 text-xs rounded-md">{s}</span>))}</div>}</div>))}</div>}
      {tab==="applications"&&<div className="space-y-4"><div className="flex gap-3 items-center flex-wrap"><select className="input w-auto" value={selectedJob||""} onChange={e=>setSelectedJob(e.target.value||null)}><option value="">Select a job…</option>{jobs.map(j=>(<option key={j.id} value={j.id}>{j.title}</option>))}</select>{selectedJob&&<button onClick={()=>bulkMut.mutate()} disabled={bulkMut.isLoading} className="btn-primary"><SparklesIcon className="w-4 h-4"/>{bulkMut.isLoading?"Screening…":"AI Bulk Screen"}</button>}</div>
      {selectedJob&&<div className="card overflow-x-auto"><table className="w-full"><thead className="border-b border-slate-100"><tr>{["Candidate","Experience","AI Score","AI Match","Status","Actions"].map(h=>(<th key={h} className="table-header">{h}</th>))}</tr></thead><tbody>
        {appsLoading?(<tr><td colSpan={6} className="text-center py-8 text-slate-400">Loading…</td></tr>):applications.length===0?(<tr><td colSpan={6} className="text-center py-8 text-slate-400">No applications yet</td></tr>):applications.map(app=>(<tr key={app.id} className="table-row">
          <td className="table-cell"><p className="font-medium text-slate-900">{app.candidateName}</p><p className="text-xs text-slate-400">{app.email}</p></td>
          <td className="table-cell">{app.totalExperience?`${app.totalExperience}y`:"—"}</td>
          <td className="table-cell">{app.aiScreeningScore!=null?(<div className="flex items-center gap-2"><div className="w-16 h-1.5 bg-slate-200 rounded-full overflow-hidden"><div className="h-full bg-primary-500 rounded-full" style={{width:`${app.aiScreeningScore}%`}}/></div><span className="text-sm font-semibold text-slate-700">{Math.round(app.aiScreeningScore)}</span></div>):<span className="text-slate-400 text-xs">Not screened</span>}</td>
          <td className="table-cell">{app.aiRecommendation?<span className="badge badge-info">{app.aiRecommendation.replace("_"," ")}</span>:"—"}</td>
          <td className="table-cell"><span className={clsx("badge",STATUS_COLOR[app.status]||"badge-neutral")}>{app.status}</span></td>
          <td className="table-cell">{!app.aiScreeningScore&&<button onClick={()=>screenMut.mutate(app.id)} disabled={screenMut.isLoading} className="text-xs text-primary-600 hover:underline flex items-center gap-1"><SparklesIcon className="w-3 h-3"/>Screen</button>}</td>
        </tr>))}
      </tbody></table></div>}</div>}
    </div>
  );
}
